={{ (() => {
  const output = $json.output;

  const SAFE_FALLBACK = 'Oi! Tudo bem? Como posso te ajudar com seu agendamento hoje?';
  const LINK_FOLLOWUP_PREFIX = 'Conseguiu abrir o link para concluir seu agendamento?\n';

  const extractSummaryUrl = (value) => {
    if (typeof value === 'object' && value !== null) {
      const url1 = typeof value.summaryUrl === 'string' ? value.summaryUrl.trim() : '';
      if (url1 && value.ok !== false) return url1;

      const url2 = typeof value?.data?.summaryUrl === 'string' ? value.data.summaryUrl.trim() : '';
      if (url2 && value?.data?.ok !== false) return url2;

      return '';
    }

    if (typeof value === 'string') {
      const match = value.match(/https?:\/\/[^\s)]+/i);
      return match ? match[0].trim() : '';
    }

    return '';
  };

  const pickText = (value) => {
    if (typeof value === 'object' && value !== null) {
      return String(value.reply || value.text || value.message || '').trim();
    }

    return typeof value === 'string' ? value.trim() : '';
  };

  const leakMatchers = [
    /we\s+are\s+the\s+assistant/i,
    /last\s+user\s+message/i,
    /user\s+writes/i,
    /system\s+ended/i,
    /follow\s+identity/i,
    /use\s+context/i,
    /patient\s+context\s+earlier/i,
    /linked\s*=\s*true/i,
    /assistant\s+provided\s+link/i,
    /prompt\s+interno/i,
    /so\s+final\s+message/i,
    /keep\s+short/i,
    /no\s+emojis/i,
    /i\'?ll\s+output\s+that/i,
    /use\s+patient\'?s\s+name/i,
    /mensagens?\s+de\s+configura[cç][aã]o/i,
  ];

  const containsPromptLeak = (value) => {
    const text = String(value ?? '').trim();
    if (!text) return false;
    return leakMatchers.some((matcher) => matcher.test(text));
  };

  const removePromptLeakLines = (value) => String(value)
    .split('\n')
    .filter((rawLine) => {
      const line = rawLine.trim();
      if (!line) return true;
      return !containsPromptLeak(line);
    })
    .join('\n');

  const sanitize = (text) => removePromptLeakLines(
    String(text ?? '')
      .replace(/\r\n/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .replace(/\s+$/gm, '')
      .trim()
      .replace(/consulta est[aá] agendada/gi, 'agendamento está pronto para conclusão')
      .replace(/consulta foi agendada/gi, 'agendamento está pronto para conclusão')
  ).trim();

  const summaryUrl = extractSummaryUrl(output);
  if (summaryUrl) {
    return `${LINK_FOLLOWUP_PREFIX}${summaryUrl}`;
  }

  const safeText = sanitize(pickText(output));

  if (!safeText || containsPromptLeak(safeText)) {
    return SAFE_FALLBACK;
  }

  return safeText;
})() }}

