={{ (() => {
  const output = $json.output;

  const getDirect = () => {
    try {
      return $('Generate Summary Link Tool').item.json;
    } catch {
      return null;
    }
  };

  const getUrl = (val) => {
    if (typeof val !== 'object' || val === null) return '';

    const url1 = typeof val.summaryUrl === 'string' ? val.summaryUrl.trim() : '';
    if (url1 && val.ok !== false) return url1;

    const data = val.data;
    const url2 = typeof data?.summaryUrl === 'string' ? data.summaryUrl.trim() : '';
    if (url2 && data?.ok !== false) return url2;

    return '';
  };

  const directUrl = getUrl(getDirect());
  if (directUrl) return directUrl;

  const outputUrl = getUrl(output);
  if (outputUrl) return outputUrl;

  if (typeof output === 'string') {
    const match = output.match(/https?:\/\/[^\s)]+/i);
    return match ? match[0].trim() : '';
  }

  return '';
})() }}

