    source = $json.output;
  } else {
    source = JSON.stringify($json);
  }

  var match = source.match(/https?:\/\/agenda\.oftleonardo\.com\.br\/([^\s)\]]+)/i);
  if (!match || !match[1]) return 'agendar/resumo';

  var suffix = String(match[1]).replace(/^\/+/, '');

  if (currentPhone && !/[?&]phone=/.test(suffix)) {
    suffix += (suffix.indexOf('?') === -1 ? '?' : '&') + 'phone=' + currentPhone;
  }

  return suffix || 'agendar/resumo';
})() }}

