const now = new Date();
const fortalezaTime = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Fortaleza',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false,
}).format(now);

const isoFormatted = now.toISOString();
const items = $input.all();

const normalizeInboundText = (payload) => {
  const message = payload?.messages?.[0];
  if (!message || typeof message !== 'object') return '';

  const type = String(message.type ?? '').toLowerCase();

  if (type === 'text') {
    return String(message?.text?.body ?? '').trim();
  }

  if (type === 'button') {
    return String(message?.button?.text ?? message?.button?.payload ?? '').trim();
  }

  if (type === 'interactive') {
    const buttonReply = message?.interactive?.button_reply;
    const listReply = message?.interactive?.list_reply;

    if (buttonReply) {
      return String(buttonReply.title ?? buttonReply.id ?? '').trim();
    }

    if (listReply) {
      return String(listReply.title ?? listReply.id ?? '').trim();
    }
  }

  return '';
};

return items
  .map((item) => {
    const message = item.json?.messages?.[0] ?? {};
    const from = String(message.from ?? '').trim();
    const inboundText = normalizeInboundText(item.json);
    const messageType = String(message.type ?? '').toLowerCase();

    if (!from || !inboundText) return null;

    return {
      json: {
        ...item.json,
        currentDateTime: fortalezaTime,
        currentDateTimeISO: isoFormatted,
        timezone: 'America/Fortaleza',
        messageType,
        inboundText,
        patientPhone: from,
        patientPhoneDigits: from.replace(/\D/g, ''),
      },
    };
  })
  .filter(Boolean);

const items = $input.all();

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const vars = /** @type {any} */ (
  typeof $vars === 'undefined' || $vars === null ? {} : $vars
);
const fetchFn = Reflect.get(globalThis, 'fetch');

for (const item of items) {
  const messageId = String(item.json?.messages?.[0]?.id ?? '').trim();
  const phoneNumberId = String(
    item.json?.metadata?.phone_number_id ??
      vars.WHATSAPP_PHONE_NUMBER_ID ??
      '989729870895780'
  ).trim();

  const token = String(
    vars.WHATSAPP_CLOUD_API_TOKEN ??
      vars.WHATSAPP_ACCESS_TOKEN ??
      ''
  ).trim();

  if (!messageId || !phoneNumberId || !token) {
    continue;
  }

  if (typeof fetchFn !== 'function') {
    console.log('Fetch API is not available in this n8n runtime.');
    continue;
  }

  try {
    const response = await fetchFn(`https://graph.facebook.com/v25.0/${phoneNumberId}/messages`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        status: 'read',
        message_id: messageId,
        typing_indicator: {
          type: 'text',
        },
      }),
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => '');
      console.log('Typing indicator failed:', response.status, errorText);
      continue;
    }

    // Small delay keeps indicator visible before sending the final reply.
    await sleep(1200);
  } catch (error) {
    console.log('Typing indicator request error:', error?.message ?? error);
  }
}

return items;
